#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long X,Y; scanf("%lld %lld",&X,&Y);
        if(Y*100<=X*107) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

